const express = require('express');
const { initTRPC } = require('@trpc/server');
const { z } = require('zod');
const { createExpressMiddleware } = require('@trpc/server/adapters/express');
const { renderTrpcPanel } = require('trpc-panel');

// Initialize tRPC v11
const t = initTRPC.create();

// Define a router with a greeting procedure
const appRouter = t.router({
  greeting: t.procedure
    .input(z.object({ name: z.string() }))
    .query(({ input }) => {
      return {
        message: `Hello, ${input.name}!`,
        timestamp: new Date().toISOString(),
      };
    }),
});

// Create Express app
const app = express();

// Create tRPC middleware
const trpcMiddleware = createExpressMiddleware({
  router: appRouter,
  createContext: () => ({}),
});

// Mount tRPC router at /trpc
app.use('/trpc', trpcMiddleware);

// Serve trpc-panel at /panel
app.get('/panel', (req, res) => {
  const panelHtml = renderTrpcPanel(appRouter, {
    url: '/trpc',
  });
  res.send(panelHtml);
});

// Start server on port 3000
const PORT = 3000;
app.listen(PORT, () => {
  console.log(`Server running on http://localhost:${PORT}`);
  console.log(`tRPC API available at http://localhost:${PORT}/trpc`);
  console.log(`trpc-panel UI available at http://localhost:${PORT}/panel`);
});

// Export the router for type inference
module.exports = { appRouter };

